parameters.jsCode:
/**
 * total_documents:
 *   cantidad de items que realmente pasaron por "Unir todo texto"
 */
const total = $items("Unir todo texto").length;

/**
 * processed_documents:
 *   cantidad de filas válidas creadas en pdf_job_rows
 */
const processed = $items("Contar documentos procesados").length;

/**
 * failed_documents:
 *   documentos detectados - documentos procesados
 *   PERO solo si realmente hubo un fallo de OCR o LLM.
 */
let failed = 0;

// Detectamos fallos reales revisando el output del LLM y del OCR
const llmItems = $items("Adjuntar Job a filas");
const ocrItems = $items("Loop Over Items");

for (let i = 0; i < total; i++) {
  const llm = llmItems[i]?.json;
  const ocr = ocrItems[i]?.json;

  const noTexto = !ocr?.text || ocr.text.trim().length === 0;
  const noLlm = llm == null || (llm.total == null && llm.confidence_score == null);
  const bajaConfianza = llm?.confidence_score < 0.8;

  if (noTexto || noLlm || bajaConfianza) {
    failed++;
  }
}

// Y nos aseguramos que failed nunca rompa processed vs total
failed = Math.min(failed, total - processed);

return [
  {
    json: {
      total_documents: total,
      processed_documents: processed,
      failed_documents: failed,
    },
  },
];

